@startuml
!theme plain

class "Client" as Client {
  <<Actor>>
}

class "Context" as Context {
  <<Actor>>
  currentState : State
  request()
}

class "State" as State {
  <<Interface>>
  handle()
}

class "StateOne" as StateOne {
  <<Actor>>
  handle()
}

class "StateTwo" as StateTwo {
  <<Actor>>
  handle()
}

Client --> Context
Context ..> State
StateOne --|> State
StateTwo --|> State

@enduml
